// Skill #50 v1.1.1 - Mandamiento #15: logs estructurados con context
// Validar exitCode + parsear stdout JSON de Claude Code CLI
const sshOutput = $input.first().json;
const traceId = `s2-cb-cc-${Date.now()}-${Math.random().toString(36).substr(2, 8)}`;
const workflowId = $workflow.id;
const timestampIso = new Date().toISOString();

// Validacion defensiva exitCode (skill #50 Mandamiento error handling)
const exitCode = sshOutput.exitCode !== undefined ? sshOutput.exitCode : sshOutput.code;
if (exitCode !== undefined && exitCode !== 0) {
  console.log(JSON.stringify({
    level: 'ERROR',
    event: 'ssh_command_failed',
    trace_id: traceId,
    workflow_id: workflowId,
    timestamp: timestampIso,
    exit_code: exitCode,
    stderr_preview: (sshOutput.stderr || '').slice(0, 500)
  }));
  throw new Error(`SSH command failed (exit ${exitCode}): ${(sshOutput.stderr || 'no stderr').slice(0, 300)}`);
}

const stdout = (sshOutput.stdout || '').trim();
if (!stdout) {
  throw new Error('SSH stdout vacio - Claude Code CLI no produjo output');
}

let claudePayload;
try {
  claudePayload = JSON.parse(stdout);
} catch (err) {
  throw new Error(`Failed to parse Claude Code stdout as JSON: ${err.message}. Raw stdout (first 500 chars): ${stdout.slice(0, 500)}`);
}

const metrics = {
  cost_usd: claudePayload.total_cost_usd || 0,
  latency_ms: claudePayload.duration_ms || 0,
  tokens_input: claudePayload.usage?.input_tokens || 0,
  tokens_output: claudePayload.usage?.output_tokens || 0
};

console.log(JSON.stringify({
  level: 'INFO',
  event: 'claude_code_aws_invocation_ok',
  trace_id: traceId,
  workflow_id: workflowId,
  timestamp: timestampIso,
  metrics: metrics
}));

return [{
  json: {
    status: 'success',
    test_name: 'TEST-Sesion2-CB-Redis-CC-AWS',
    claude_code_response: claudePayload.result || claudePayload.response || '',
    metrics: metrics,
    timestamp: timestampIso,
    trace_id: traceId
  }
}];
